/**
 * gi-docgen navigation script.
 *
 * Reads the shallow NavigationElement[] from window.navigationData
 * (generated by GiDocgenTheme.getNavigation — max 2 levels, no "default" entries,
 * scope wrapper already stripped) and builds the sidebar DOM as accordions.
 */

async function decompressJson(base64Data) {
	const binaryData = Uint8Array.from(atob(base64Data), (c) => c.charCodeAt(0));
	const blob = new Blob([binaryData]);
	const decompressedStream = blob.stream().pipeThrough(new DecompressionStream("deflate"));
	const decompressedText = await new Response(decompressedStream).text();
	return JSON.parse(decompressedText);
}

function getCurrentPath() {
	return window.location.pathname;
}

function isCurrentPage(path) {
	if (!path) return false;
	const base = document.documentElement.dataset.base ?? "./";
	const absPath = new URL(path, new URL(base, window.location.href)).pathname;
	return getCurrentPath() === absPath;
}

function resolveHref(path) {
	const base = document.documentElement.dataset.base ?? "./";
	return new URL(path, new URL(base, window.location.href)).href;
}

function makeIcon(kind) {
	const svg = document.createElementNS("http://www.w3.org/2000/svg", "svg");
	svg.setAttribute("width", "20");
	svg.setAttribute("height", "20");
	svg.setAttribute("viewBox", "0 0 24 24");
	svg.setAttribute("fill", "none");
	svg.setAttribute("aria-hidden", "true");
	const use = document.createElementNS("http://www.w3.org/2000/svg", "use");
	use.setAttribute("href", `#icon-${kind}`);
	svg.appendChild(use);
	return svg;
}

function makeLink(text, path, kind, isCurrent) {
	const a = document.createElement("a");
	a.href = resolveHref(path);
	if (kind != null) a.appendChild(makeIcon(kind));
	a.appendChild(document.createTextNode(text));
	if (isCurrent) a.classList.add("current");
	return a;
}

function isInSubtree(pkg) {
	if (isCurrentPage(pkg.path)) return true;
	return (pkg.children ?? []).some((c) => isCurrentPage(c.path));
}

function renderPackage(pkg) {
	const isCurrent = isInSubtree(pkg);

	const li = document.createElement("li");
	const details = document.createElement("details");
	details.className = "tsd-accordion";
	if (isCurrent) details.open = true;

	const summary = document.createElement("summary");
	summary.className = "tsd-accordion-summary";
	summary.dataset.key = `pkg-${pkg.text}`;

	const chevron = document.createElementNS("http://www.w3.org/2000/svg", "svg");
	chevron.setAttribute("width", "16");
	chevron.setAttribute("height", "16");
	chevron.setAttribute("viewBox", "0 0 24 24");
	chevron.setAttribute("fill", "none");
	chevron.setAttribute("aria-hidden", "true");
	const chevronUse = document.createElementNS("http://www.w3.org/2000/svg", "use");
	chevronUse.setAttribute("href", "#icon-chevronDown");
	chevron.appendChild(chevronUse);
	summary.appendChild(chevron);

	if (pkg.kind != null) summary.appendChild(makeIcon(pkg.kind));

	if (pkg.path) {
		summary.appendChild(makeLink(pkg.text, pkg.path, null, isCurrentPage(pkg.path)));
	} else {
		summary.appendChild(document.createTextNode(pkg.text));
	}

	details.appendChild(summary);

	const div = document.createElement("div");
	const ul = document.createElement("ul");
	ul.className = "tsd-small-nested-navigation";

	for (const child of pkg.children ?? []) {
		const childLi = document.createElement("li");
		if (child.path) {
			childLi.appendChild(makeLink(child.text, child.path, child.kind, isCurrentPage(child.path)));
		} else {
			const span = document.createElement("span");
			if (child.kind != null) span.appendChild(makeIcon(child.kind));
			span.appendChild(document.createTextNode(child.text));
			childLi.appendChild(span);
		}
		ul.appendChild(childLi);
	}

	div.appendChild(ul);
	details.appendChild(div);
	li.appendChild(details);
	return li;
}

/** Waits until window.navigationData is available (navigation.js may load async). */
function waitForNavigationData() {
	if (window.navigationData) return Promise.resolve();
	return new Promise((resolve) => {
		const script = document.getElementById("tsd-nav-script");
		if (script) {
			script.addEventListener("load", resolve, { once: true });
		} else {
			// Fallback: poll until available
			const interval = setInterval(() => {
				if (window.navigationData) {
					clearInterval(interval);
					resolve();
				}
			}, 50);
		}
	});
}

async function buildNav() {
	await waitForNavigationData();
	if (!window.navigationData) return;

	const container = document.getElementById("tsd-nav-container");
	if (!container) return;

	const nav = await decompressJson(window.navigationData);

	container.innerHTML = "";
	for (const pkg of nav) {
		container.appendChild(renderPackage(pkg));
	}

	window.app?.createComponents?.(container);
}

buildNav();
